#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices[DEFAULT_ORDER + 1];
	int keys[DEFAULT_ORDER + 1];
	char is_leaf;
	int num_keys;
} knode;

__kernel void findK(__private long maxheight,
                    __global knode *knodes,
                    __private long knodes_elem,
                    __global record *records,
                    __global long *currKnode,
                    __global long *offset,
                    __global int *keys,
                    __global record *ans) {
	int thid = (int)get_local_id(0);
	int bid = (int)get_group_id(0);

	for (long i = 0; i < maxheight; i++) {
		long curr = currKnode[bid];
		int key = keys[bid];

		if (key >= knodes[curr].keys[thid] && key < knodes[curr].keys[thid + 1]) {
			int idx = knodes[curr].indices[thid];
			if (knodes_elem > (long)idx) {
				offset[bid] = (long)idx;
			}
		}

		barrier(CLK_GLOBAL_MEM_FENCE);
		if (thid == 0) {
			currKnode[bid] = offset[bid];
		}
		barrier(CLK_GLOBAL_MEM_FENCE);
	}

	long curr = currKnode[bid];
	int key = keys[bid];
	if (key == knodes[curr].keys[thid]) {
		int rec_idx = knodes[curr].indices[thid];
		ans[bid].value = records[rec_idx].value;
	}
}

